import{_ as a}from"./chunks/avatar.BY6p2DuL.js";import{_ as t,o as i,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"About","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1775127256000}'),o={name:"about.md"};function s(l,e,c,h,u,p){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><div class="profile-header"><img src="'+a+'" alt="Qi Meng" class="profile-avatar"><div class="profile-info"><h1>Qi Meng</h1><div class="title">Condensed Matter Physics | Ph.D. Candidate</div><div class="profile-links"><a href="mailto:mengq8@mail2.sysu.edu.cn">Email</a><a href="https://github.com/qimeng0103" target="_blank">GitHub</a><a href="https://www.researchgate.net/profile/Qi-Meng-44" target="_blank">ResearchGate</a><a href="https://orcid.org/0009-0000-8564-7601" target="_blank">ORCID</a></div></div></div><h2 id="research-interests" tabindex="-1">Research Interests <a class="header-anchor" href="#research-interests" aria-label="Permalink to &quot;Research Interests&quot;">​</a></h2><p>My research focuses on theoretical and computational condensed matter physics, with particular emphasis on:</p><div class="research-areas"><h4>Topological Superconductivity</h4><p>Theoretical studies of topological superconductors, Majorana zero modes, and non-Abelian anyons</p><h4>Topological Quantum Computation</h4><p>Quantum information processing based on Majorana fermions and topological protection</p><h4>Quantum Simulation</h4><p>Quantum simulation of many-body systems using superconducting quantum processors</p></div><h2 id="education" tabindex="-1">Education <a class="header-anchor" href="#education" aria-label="Permalink to &quot;Education&quot;">​</a></h2><ul><li><p><strong>Ph.D. in Physics</strong> (2026–Present)<br> Eastern Institute of Technology, Ningbo<br> Advisor: Tong Zhou</p></li><li><p><strong>M.S. in Nuclear Science and Technology</strong> (2023–2026)<br> Sino-French Institute of Nuclear Engineering and Technology, Sun Yat-sen University, Zhuhai</p></li><li><p><strong>B.S. in Nuclear Engineering</strong> (2019–2023)<br> Sino-French Institute of Nuclear Engineering and Technology, Sun Yat-sen University, Zhuhai</p></li></ul><h2 id="publications" tabindex="-1">Publications <a class="header-anchor" href="#publications" aria-label="Permalink to &quot;Publications&quot;">​</a></h2><div class="publications-list"><li><div class="publication-title">See <a href="https://www.researchgate.net/profile/Qi-Meng-44" target="_blank">ResearchGate</a> or <a href="https://orcid.org/0009-0000-8564-7601" target="_blank">ORCID</a> for full publication list</div></li></div><h2 id="technical-skills" tabindex="-1">Technical Skills <a class="header-anchor" href="#technical-skills" aria-label="Permalink to &quot;Technical Skills&quot;">​</a></h2><p><strong>Programming Languages:</strong> Python, Julia, Mathematica, MATLAB</p><h2 id="exam-preparation-materials" tabindex="-1">Exam Preparation Materials <a class="header-anchor" href="#exam-preparation-materials" aria-label="Permalink to &quot;Exam Preparation Materials&quot;">​</a></h2><p><strong>USTC PhD Physics Exam Prep</strong> — Personal study notes for University of Science and Technology of China (USTC) Physics Ph.D. entrance examination.</p><p>📄 <a href="/exam-prep/ustc-phd-prep.pdf">Download PDF</a> <em>(Last updated: 2026-04-14)</em></p><p><strong>Contents:</strong></p><ul><li>Core physical models with quick recognition guides</li><li><strong>Zeng Jinyan QM Chapter 3:</strong> Bound state existence conditions (1D symmetric/semi-infinite wells, δ-potential, 3D spherical well)</li><li><strong>Zeng Jinyan QM Chapter 4:</strong> Resonance states &amp; quasi-bound states (Breit-Wigner formula, barrier transmission, decaying states)</li><li><strong>Zeng Jinyan QM Chapter 5:</strong> Scattering theory (double-barrier resonance, partial wave analysis, scattering length, Levinson&#39;s theorem, effective range expansion)</li><li>Stationary perturbation theory (non-degenerate &amp; degenerate)</li><li>Problem-solving techniques and decision trees</li><li>Secondary conclusions and quick-reference formulas (QM, stat mech, solid state, scattering, Green&#39;s functions)</li><li>Detailed derivations in appendix (perturbation theory, Stark effect)</li><li>Error &amp; mental block library</li></ul><p><strong>Format:</strong> Chinese main text with English terminology notes, Beamer-style colored boxes for high-density review</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><ul><li><strong>Email:</strong> <a href="mailto:mengq8@mail2.sysu.edu.cn" target="_blank" rel="noreferrer">mengq8@mail2.sysu.edu.cn</a></li><li><strong>GitHub:</strong> <a href="https://github.com/qimeng0103" target="_blank" rel="noreferrer">@qimeng0103</a></li><li><strong>ResearchGate:</strong> <a href="https://www.researchgate.net/profile/Qi-Meng-44" target="_blank" rel="noreferrer">Qi Meng</a></li><li><strong>ORCID:</strong> <a href="https://orcid.org/0009-0000-8564-7601" target="_blank" rel="noreferrer">0009-0000-8564-7601</a></li></ul><hr><blockquote><p><em>&quot;The first principle is that you must not fool yourself — and you are the easiest person to fool.&quot;</em></p><p>— Richard Feynman</p></blockquote>',21)])])}const f=t(o,[["render",s]]);export{m as __pageData,f as default};
